"use strict";

// ============================================================
// LeetCode 153. 寻找旋转排序数组中的最小值 (Find Minimum in Rotated Sorted Array)
// ============================================================
// 条件：一个原本升序的数组在某个未知位置旋转了一次，元素无重复。
// 例如：[0,1,2,4,5,6,7] 旋转为 [4,5,6,7,0,1,2]，最小值 0。
// 方法：二分查找 — 比较 nums[mid] 和 nums[right]。
// 时间：O(log n)  空间：O(1)
// ============================================================
function findMin(nums) {
  var left = 0;
  var right = nums.length - 1;

  while (left < right) {
    var mid = Math.floor((left + right) / 2);

    if (nums[mid] > nums[right]) {
      // mid 在左半段（较大那半），最小值一定在右边
      left = mid + 1;
    } else {
      // mid 在右半段（较小那半），最小值可能是 mid 或在左边
      right = mid;
    }
  }

  return nums[left];
} // ----------------------------------------------------------
// 图解：
//
// nums = [4, 5, 6, 7, 0, 1, 2]
//
// mid=3, nums[3]=7 > nums[6]=2 → mid在左半 → left=4,right=6
//                 [0, 1, 2]
// mid=5, nums[5]=1 < nums[6]=2 → mid在右半 → right=5,left=4
//                 [0, 1]
// mid=4, nums[4]=0 < nums[5]=1 → mid在右半 → right=4,right=4
//
// left=right=4, nums[4]=0 ✓
// ----------------------------------------------------------
// ============================================================
// 为什么和右边比，不和左边比？
// ============================================================
// 和左边比（nums[mid] >= nums[left]）在无旋转数组会出 bug：
//
// 无旋转 [0,1,2,4,5,6,7]：
//   nums[mid] >= nums[left] 永远为 true（因为 left 指向最小值）
//   → left 一路无脑右移 → 直接跳过最小值 0 → 返回 7 ❌
//
// 和右边比（nums[mid] > nums[right]）：
//   无旋转时 nums[mid] < nums[right] 始终成立
//   → right 稳稳向左收缩 → 返回 0 ✅
//   旋转时 nums[mid] > nums[right] 可能成立
//   → left 向右跳 → 也能找到最小值 ✅
//
// 结论：两个场景给不同的布尔值，所以和右边比能区分。和左边比区分不了。
// ============================================================
// LeetCode 154. 寻找旋转排序数组中的最小值 II（有重复元素）
// ============================================================
// 条件：和 153 一样，但数组可能有重复元素。
// 方法：多一种 nums[mid] === nums[right] 的情况，无法判断时 right--。
// 时间：平均 O(log n)，最坏 O(n)（全是相同元素）  空间：O(1)
// ============================================================


function findMin2(nums) {
  var left = 0;
  var right = nums.length - 1;

  while (left < right) {
    var mid = Math.floor((left + right) / 2);

    if (nums[mid] > nums[right]) {
      left = mid + 1;
    } else if (nums[mid] < nums[right]) {
      right = mid;
    } else {
      // nums[mid] === nums[right]，无法判断 mid 在左还是右
      // 收缩右边界一步（因为 nums[right] 至少有一个等值备份在 mid 处）
      right--;
    }
  }

  return nums[left];
} // ----------------------------------------------------------
// 为什么相等时 right-- 是安全的？
//
// [3, 3, 1, 3], left=0, right=3
// mid=1, nums[1]=3, nums[3]=3 → 相等，right--
// right=2, nums = [3, 3, 1]（最小值 1 还在）
// mid=1, nums[1]=3 > nums[2]=1 → left=2
// left=right=2, nums[2]=1 ✓
// ----------------------------------------------------------
// ============================================================
// 对比总结
// ============================================================
// |             | 153. 找最小值（无重复）  | 154. 找最小值（有重复）       |
// |-------------|------------------------|----------------------------|
// | 条件        | 无重复元素              | 可能有重复元素              |
// | 核心比较    | nums[mid] vs nums[right] | 同左 + nums[mid]===nums[right] |
// | 相等处理    | 不出现                 | right-- 收缩               |
// | 时间        | O(log n)              | 平均 O(log n)，最坏 O(n)    |
// ============================================================
// 测试
// ============================================================


console.log("153. 寻找旋转排序数组中的最小值（无重复）:");
console.log("  [4,5,6,7,0,1,2]   →", findMin([4, 5, 6, 7, 0, 1, 2])); // 0

console.log("  [3,4,5,1,2]       →", findMin([3, 4, 5, 1, 2])); // 1

console.log("  [11,13,15,17]     →", findMin([11, 13, 15, 17])); // 11（无旋转）

console.log("154. 寻找旋转排序数组中的最小值 II（有重复）:");
console.log("  [2,2,2,0,1]       →", findMin2([2, 2, 2, 0, 1])); // 0

console.log("  [3,3,1,3]         →", findMin2([3, 3, 1, 3])); // 1